import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch8: ScenarioQuestion[] = [
  q("sq-bg8-1",ip,"behavioral","You are asked about your experience with electronic health records.","How comfortable are you with EHR systems?","I have extensive experience with Epic from my clinical rotations and prior CNA work. I am proficient in documentation, order entry, medication administration records, and data retrieval. I adapt quickly to new systems and completed supplemental training in our simulation lab. I view technology as a tool that enhances nursing care when used effectively.","Technology proficiency with adaptability.","beginner"),
  q("sq-bg8-2",ip,"behavioral","You demonstrated cultural sensitivity during a clinical experience.","How do you provide culturally sensitive care?","I cared for a Somali family whose cultural norms included only female healthcare providers for the patient. I ensured all assigned staff were female, coordinated with the interpreter for cultural nuances beyond language, and learned about their dietary requirements. The family expressed deep gratitude for the respect shown to their cultural practices.","Proactive cultural accommodation.","beginner"),
  q("sq-bg8-3",ip,"clinical_judgment","A patient on warfarin develops a nosebleed that will not stop.","How would you manage epistaxis in an anticoagulated patient?","I would apply direct pressure by pinching the nostrils for 10-15 minutes, position the patient leaning forward to prevent blood swallowing, apply ice to the bridge of the nose, check the INR level, and notify the provider. If bleeding is severe, I would prepare for possible nasal packing and anticipate INR reversal with vitamin K. I would also assess for other bleeding signs.","Anticoagulation-related bleeding management.","intermediate"),
  q("sq-bg8-4",ip,"clinical_judgment","A patient with COPD on 2L nasal cannula has a SpO2 of 88%.","Is this oxygen saturation acceptable for this patient?","For COPD patients, a target SpO2 of 88-92% is often acceptable and even preferred. Higher oxygen levels can suppress the hypoxic drive in COPD patients, leading to CO2 retention and respiratory failure. I would assess the patient's baseline saturation, symptoms, and respiratory status before adjusting oxygen. I would not increase oxygen without provider guidance.","COPD-specific oxygen target understanding.","intermediate"),
  q("sq-bg8-5",ip,"clinical_judgment","A patient with celiac disease develops a rash after consuming gluten.","What is dermatitis herpetiformis?","Dermatitis herpetiformis is an intensely itchy, blistering skin manifestation of celiac disease triggered by gluten ingestion. I would assess the rash distribution (typically elbows, knees, buttocks), provide comfort measures for itching, ensure strict gluten elimination from the patient's diet, and notify the provider for possible dapsone therapy. I would reinforce dietary education.","Celiac disease dermatologic manifestation.","intermediate"),
  q("sq-bg8-6",ip,"clinical_judgment","A patient develops Kussmaul respirations.","What do Kussmaul respirations indicate?","Kussmaul respirations—deep, rapid breathing—represent the body's attempt to compensate for metabolic acidosis by blowing off CO2. Common causes include diabetic ketoacidosis, renal failure, and severe sepsis. I would check blood glucose, obtain ABG and metabolic panel, check ketones if DKA is suspected, and notify the provider immediately. Kussmaul breathing is a sign of serious metabolic derangement.","Kussmaul respirations as metabolic acidosis compensation.","intermediate"),
  q("sq-bg8-7",ip,"clinical_judgment","A patient with Parkinson's disease falls repeatedly despite interventions.","How would you approach recurrent falls in a Parkinson's patient?","I would reassess the fall pattern: timing related to medication peaks and troughs, environmental factors, and gait instability severity. I would coordinate with PT for Parkinson's-specific gait training, review medication timing with the neurologist, implement environmental modifications, and consider assistive devices. Falls in Parkinson's often correlate with medication fluctuations and can be optimized through timing adjustments.","Parkinson's-specific fall prevention strategies.","advanced"),
  q("sq-bg8-8",ip,"scenario_responses","A patient asks why they need to be weighed every day.","How would you explain daily weight monitoring?","I would explain: 'Daily weights help us monitor fluid balance—sudden weight gain can indicate your body is retaining fluid, which may affect your heart or kidneys. A gain of 2-3 pounds overnight could mean we need to adjust your medications. It is one of the most important monitoring tools we have, especially for your condition.'","Patient-friendly explanation of clinical monitoring rationale.","beginner"),
  q("sq-bg8-9",ws,"prioritization","A patient is actively vomiting while another needs a scheduled medication.","Which patient takes priority?","The vomiting patient takes priority—I need to assess for airway compromise, aspiration risk, provide an emesis basin, position them safely, and evaluate the cause. Vomiting can indicate serious complications. The scheduled medication can be safely given within the acceptable time window after I stabilize the vomiting patient.","Acute symptom management before scheduled tasks.","beginner"),
  q("sq-bg8-10",ws,"prioritization","You have a patient who needs a stat medication and another whose IV pump is beeping.","How do you prioritize stat orders versus alarms?","Stat medication indicates clinical urgency—a provider has determined this medication is needed immediately. I would administer the stat medication first, then address the IV pump alarm. However, I would quickly assess the alarm type—if it indicates air in the line or upstream occlusion, that may need immediate attention. A simple end-of-bag alarm can wait.","Stat order priority with alarm triage.","beginner"),
  q("sq-bg8-11",ws,"delegation","You need to delegate ambulation to a CNA for a patient with an IV pole and oxygen.","How would you delegate complex ambulation?","I would provide specific instructions: 'Mr. Garcia needs to walk to the end of the hall and back with his IV pole and portable oxygen. Please make sure the oxygen tubing does not get tangled with the IV tubing. Walk beside him on his weaker side. If his oxygen drops below 90% on the portable monitor or he becomes short of breath, stop and let me know immediately.'","Equipment-aware ambulation delegation.","beginner"),
  q("sq-bg8-12",ws,"patient_safety","A patient with a known allergy to latex undergoes a procedure with latex gloves used.","How would you prevent a latex allergy reaction during a procedure?","I would ensure the procedure room is latex-free: non-latex gloves, equipment, and supplies. I would verify all team members are aware of the allergy. I would have emergency medications available. I would place a prominent allergy alert on the chart, room door, and patient wristband. If latex exposure occurred accidentally, I would treat the reaction immediately.","Comprehensive latex-free environment preparation.","intermediate"),
  q("sq-bg8-13",ws,"medication_error","You discover that a patient has been receiving a medication they are not prescribed.","How would you address a patient receiving an unordered medication?","I would stop the medication immediately, assess the patient for adverse effects, review the MAR and order records to identify how the error occurred, notify the provider with details about the medication and duration of administration, and complete an incident report. I would also assess if the unintended medication interacted with any of their prescribed medications.","Unordered medication discovery and investigation.","intermediate"),
  q("sq-bg8-14",ws,"handoff_communication","You are giving report to a nurse who has never worked on your specialty unit before.","How would you tailor handoff for a non-specialty nurse?","I would provide additional context about specialty-specific equipment, protocols, and assessment parameters. I would explain unfamiliar terminology, identify key complications to watch for, and provide reference resources. I would offer my phone number for questions during the shift. Tailored handoff for non-specialty nurses prevents knowledge gaps from becoming patient safety gaps.","Specialty-adapted handoff communication.","intermediate"),
  q("sq-bg8-15",ws,"difficult_coworkers","A colleague rolls their eyes when you contribute during team meetings.","How would you address dismissive nonverbal behavior?","I would address it privately: 'I have noticed some nonverbal responses when I speak during meetings. If you have concerns about my contributions, I would welcome direct feedback so I can improve. I want to contribute meaningfully to our team discussions.' If the behavior continued, I would document it and discuss with the manager.","Addressing dismissive body language directly.","intermediate"),
  q("sq-bg8-16",ws,"interdisciplinary_communication","The case manager is pushing for discharge but nursing assessment indicates the patient is not ready.","How would you advocate against premature discharge?","I would present my clinical findings objectively: 'My assessment shows the patient cannot ambulate independently to the bathroom, has not demonstrated understanding of their medication regimen, and their blood pressure remains labile. I believe discharging today creates a readmission risk. Can we discuss specific criteria that need to be met before safe discharge?'","Clinical data-based discharge readiness advocacy.","intermediate"),
  q("sq-bg8-17",ct,"first_shift","Your unit uses a buddy system for new nurses.","How would you make the most of a buddy nurse system?","I would identify my buddy nurse's strengths and learning opportunities. I would share my patient information proactively so they can provide backup. I would offer reciprocal help. I would communicate honestly about my comfort level with different tasks. The buddy system works best as a partnership, not a dependency—both nurses should benefit.","Collaborative buddy system utilization.","beginner"),
  q("sq-bg8-18",ct,"new_nurse_anxiety","You are afraid of making a medication error.","How would you manage medication error anxiety?","I would follow the systematic approach every single time: five rights, barcode scanning, independent double-checks for high-alert medications, and questioning anything that does not seem right. I would recognize that the system is designed with multiple safety barriers. I would not let anxiety cause me to rush—speed increases error risk. Consistent, methodical practice is the best error prevention.","Systematic safety barriers for medication confidence.","beginner"),
  q("sq-bg8-19",ct,"time_management","You are consistently running 30 minutes late at end of shift.","How would you address chronic overtime?","I would analyze where time is lost: documentation, medication passes, or unexpected events. I would implement earlier charting, better time clustering, and delegation of appropriate tasks. I would seek workflow tips from nurses who leave on time. I would communicate with my charge nurse if the workload is genuinely excessive. Chronic overtime indicates a workflow issue that needs systematic resolution.","Overtime root cause analysis.","beginner"),
  q("sq-bg8-20",ct,"documentation_challenges","You need to document a patient who refuses all care.","How would you document complete care refusal?","I would document: the specific care refused, my explanation of risks and consequences, the patient's stated reason for refusal, their mental status at the time, any alternative care offered, provider notification, and the patient's continued refusal after education. I would have the patient sign a refusal of care form if possible. Thorough refusal documentation protects both the patient and the nurse.","Comprehensive care refusal documentation.","intermediate"),
  q("sq-bg8-21",ct,"critical_thinking_drills","A patient's CRP level is 150 mg/L.","What does a markedly elevated CRP indicate?","CRP (C-reactive protein) above 100 mg/L strongly suggests serious bacterial infection or significant tissue inflammation. Normal is below 3 mg/L. Unlike ESR, CRP rises and falls rapidly with acute changes. I would correlate with clinical presentation, assess for infection sources, ensure appropriate cultures are obtained, and monitor CRP trends as a treatment response marker.","CRP as acute inflammation marker.","intermediate"),
  q("sq-bg8-22",ct,"critical_thinking_drills","A patient's platelet count is 25,000.","What are the risks of severe thrombocytopenia?","Platelet count below 50,000 increases bleeding risk; below 20,000 poses risk for spontaneous hemorrhage, including intracranial bleeding. I would implement bleeding precautions: soft toothbrush, no razor shaving, avoid IM injections and rectal procedures, hold anticoagulants, apply prolonged pressure to puncture sites, and monitor for petechiae, bruising, and occult blood. I would anticipate possible platelet transfusion.","Severe thrombocytopenia management.","advanced"),
  q("sq-bg8-23",pd,"professional_boundaries","A former patient runs into you at a restaurant.","How would you handle encountering a former patient socially?","I would acknowledge them warmly but briefly. I would not discuss their medical history or treatment in public. I would follow their lead on the interaction—some patients want to chat, others prefer privacy. I would not share clinical information about our previous relationship with my companions. A brief, friendly acknowledgment is appropriate.","Social encounter boundary management.","beginner"),
  q("sq-bg8-24",pd,"ethical_dilemmas","A patient wants a medical procedure their physician believes is unnecessary.","How would you navigate patient-desired but medically unnecessary procedures?","I would ensure the patient has received thorough education about why the procedure is not recommended. I would explore the patient's underlying concerns—often the desire stems from fear or misinformation. I would facilitate clear physician-patient communication. Ultimately, patient autonomy is respected, but informed decision-making requires understanding the medical perspective.","Balancing autonomy with medical judgment.","intermediate"),
  q("sq-bg8-25",pd,"workplace_bullying","A nurse makes fun of new graduates behind their backs.","How would you address generational nursing bullying?","I would confront the behavior: 'Making fun of new graduates creates a hostile environment and discourages them from asking questions, which affects patient safety. I think we should be supporting new nurses, not ridiculing them.' I would model inclusive behavior. If the culture is pervasive, I would advocate for a formal anti-bullying initiative through nursing leadership.","Culture-level anti-bullying advocacy.","intermediate"),
  q("sq-bg8-26",pd,"advocacy","A patient cannot read and needs medication instructions.","How would you ensure medication safety for an illiterate patient?","I would use verbal instruction with teach-back, create picture-based medication charts showing pill appearance with administration times, involve a family member or caregiver, arrange for home health follow-up, and contact the pharmacy about blister-pack packaging. I would not assume the patient can read any written materials—I would verify their preferred learning method.","Literacy-sensitive medication education.","beginner"),
  q("sq-bg8-27",pd,"patient_communication","A patient asks you to explain their diagnosis in plain English.","How would you translate medical terminology for patients?","I would use everyday language: 'Heart failure does not mean your heart stopped—it means your heart is not pumping as strongly as it should. Think of it like a pump that is working but not at full power. We are using medications to help it work more efficiently.' I would check understanding, encourage questions, and avoid medical jargon entirely.","Plain language medical translation.","beginner"),
  q("sq-bg8-28",cn,"job_offer_negotiation","You want to negotiate for a specific specialty training program.","How would you request specialty training in your offer?","I would express it as a mutual investment: 'I am drawn to your unit's cardiac program. Would you consider including cardiac monitoring certification and ACLS within my first year as part of my development plan? These certifications would increase my value to the unit and improve patient outcomes on your cardiac floor.'","Mutual-benefit specialty training request.","beginner"),
  q("sq-bg8-29",cn,"probation_period","You are offered overtime during probation.","Should you accept overtime during your probation period?","I would be strategic: occasional overtime shows willingness and provides additional learning time. However, excessive overtime during probation risks burnout and increases error risk during the learning curve. I would accept selectively, ensuring I maintain the energy and focus needed for safe patient care. I would communicate my reasoning to the charge nurse.","Strategic overtime acceptance during orientation.","beginner"),
  q("sq-bg8-30",cn,"career_advancement","You are interested in perioperative nursing.","How would you pursue a perioperative nursing career?","I would seek a perioperative internship program or OR orientation. I would pursue CNOR certification, learn about sterile technique, surgical instrumentation, and anesthesia support. I would develop comfort with high-acuity situations and time-critical decision-making. Perioperative nursing offers diverse specialties within one setting: circulating, scrub, PACU, and pre-op assessment.","Perioperative nursing career pathway.","intermediate"),
  q("sq-bg8-31",ip,"clinical_judgment","A patient with a pulmonary artery catheter has a wedge pressure of 24 mmHg.","What does an elevated PCWP indicate?","Pulmonary capillary wedge pressure (normal 8-12 mmHg) of 24 indicates elevated left atrial pressure, typically from left heart failure or fluid overload. I would assess for pulmonary edema signs, administer diuretics as ordered, restrict fluids, monitor urine output, and notify the provider. PCWP trends guide heart failure treatment decisions—it is a key hemodynamic parameter.","PCWP interpretation for heart failure management.","advanced"),
  q("sq-bg8-32",ws,"patient_safety","A patient with a peanut allergy is given a medication containing peanut oil.","How would you manage an allergen-containing medication administration?","I would hold the medication, check for allergic reaction symptoms, notify the provider and pharmacist about the allergen content, and request an alternative formulation. I would document the allergen concern. Some medications contain hidden allergens (peanut oil, soy, egg protein, latex) that are not immediately obvious. Pharmacist review of allergen content is essential for allergic patients.","Hidden allergen identification in medications.","intermediate"),
  q("sq-bg8-33",ct,"critical_thinking_drills","A patient's B12 level is 100 pg/mL.","What does a low B12 level indicate?","B12 of 100 (normal 200-900 pg/mL) indicates deficiency that can cause megaloblastic anemia, peripheral neuropathy, cognitive impairment, and glossitis. Common causes include pernicious anemia, vegetarian/vegan diet, malabsorption conditions, or gastric surgery. I would assess for neurological symptoms, check CBC for macrocytic anemia, and notify the provider for B12 replacement (usually IM injection for severe deficiency).","B12 deficiency assessment and replacement.","beginner"),
  q("sq-bg8-34",pd,"ethical_dilemmas","You discover a clinical trial patient is not being given true informed consent.","How would you address informed consent concerns in research?","I would ensure the patient understands the experimental nature of their treatment, the alternatives available, and the risks involved. I would report my concerns to the research ethics board (IRB) and the principal investigator. Research participants have the right to withdraw at any time. I would not participate in research that violates informed consent principles.","Research ethics advocacy.","advanced"),
  q("sq-bg8-35",cn,"performance_evaluation","You want feedback on specific clinical skills.","How would you request targeted clinical feedback?","I would ask specifically: 'I would appreciate feedback on three areas: my IV insertion technique, my SBAR communication with physicians, and my time management during medication passes. What specific improvements would make the biggest difference in my practice?' Targeted questions generate more useful feedback than asking 'How am I doing?'","Specific feedback requests for targeted improvement.","beginner"),
  q("sq-bg8-36",ip,"clinical_judgment","A patient develops Stevens-Johnson syndrome after starting a new medication.","How would you manage Stevens-Johnson syndrome?","SJS is a medical emergency involving severe skin and mucous membrane reactions. I would stop the offending medication immediately, provide aggressive wound care similar to burn management, ensure IV fluid resuscitation, administer pain management, protect the airway, and notify the provider for possible ICU transfer. SJS requires specialized dermatology and possible burn center care due to the extent of skin involvement.","SJS emergency management.","advanced"),
  q("sq-bg8-37",ws,"handoff_communication","You need to hand off a patient with active family conflict.","How would you communicate family dynamics during handoff?","I would include family dynamics in my report: 'The patient's daughter and son disagree about the care plan. The daughter wants aggressive treatment; the son supports comfort care. The patient has capacity and has expressed preference for comfort measures. A family meeting is scheduled for tomorrow. Limit information sharing to the patient's authorized contacts per the HIPAA form.'","Family dynamic communication during handoff.","intermediate"),
  q("sq-bg8-38",ct,"first_shift","You are unsure how to operate the patient-controlled analgesia pump.","How would you handle equipment unfamiliarity?","I would not operate equipment I am not trained on. I would ask my preceptor for a demonstration, review the equipment's quick-reference guide, and practice with the pump before using it on a patient. I would also ensure I understand the safety features—lockout intervals, dose limits, and alarm settings. Equipment competency is non-negotiable for patient safety.","Equipment competency verification before use.","beginner"),
  q("sq-bg8-39",pd,"patient_communication","A family member is taking extensive notes during your patient education.","How would you support a note-taking family member?","I would encourage their engagement: 'I am glad you are taking notes—that will be very helpful after discharge. Let me slow down so you can capture the key points. I will also provide written materials to supplement your notes.' I would offer to review their notes for accuracy. Active family involvement in education improves post-discharge care quality.","Supporting family engagement in education.","beginner"),
  q("sq-bg8-40",cn,"career_advancement","You want to develop expertise in emergency nursing.","How would you prepare for emergency nursing?","I would obtain CEN certification, pursue TNCC and ENPC training, develop rapid triage skills, and gain experience in high-acuity settings. Emergency nursing requires comfort with ambiguity, rapid clinical decision-making, and the ability to manage multiple critically ill patients simultaneously. I would also develop proficiency in procedural skills common in the ED.","Emergency nursing specialization pathway.","intermediate"),
  q("sq-bg8-41",ip,"clinical_judgment","A patient with suspected meningitis presents with neck stiffness, fever, and photophobia.","What immediate interventions are needed for suspected meningitis?","I would implement droplet precautions, draw blood cultures before antibiotics, ensure lumbar puncture supplies are available, administer empiric antibiotics as ordered (time-critical—do not wait for LP results), provide a darkened quiet environment, administer analgesics, and monitor neurological status closely. Bacterial meningitis mortality increases with antibiotic delay—antibiotics should be given within 30 minutes of suspicion.","Meningitis emergency with time-critical antibiotics.","advanced"),
  q("sq-bg8-42",ws,"delegation","You need to delegate post-operative vital sign monitoring with specific parameters.","How would you delegate post-op vital sign monitoring?","I would specify: 'Check vital signs every 15 minutes for the first hour, then every 30 minutes for the next 2 hours. Notify me immediately if: systolic BP drops below 90 or rises above 180, heart rate goes above 120 or below 50, temperature exceeds 101°F, or oxygen saturation drops below 92%. Also report any drainage on the surgical dressing.'","Parameter-specific post-operative vital sign delegation.","beginner"),
  q("sq-bg8-43",ws,"medication_error","A patient questions why they are getting a different number of pills than usual.","How would you handle a patient questioning pill count?","I would stop and verify. Patients who take daily medications often know their regimen better than we realize. I would recheck the order, compare to the MAR, and verify with pharmacy if there is a discrepancy. I would not dismiss the patient's concern. A patient questioning pill count is an additional safety barrier that should be appreciated and investigated.","Patient as safety partner in medication verification.","beginner"),
  q("sq-bg8-44",ct,"time_management","You have four patients and one is monopolizing your time with non-urgent conversation.","How would you manage a talkative patient without being rude?","I would set caring boundaries: 'I enjoy talking with you, and I want to give you the attention you deserve. Right now I need to check on my other patients to make sure they are safe. I will come back during my next round and we can talk more then.' Setting expectations while showing genuine care maintains the relationship without compromising other patients' care.","Compassionate time boundaries with talkative patients.","beginner"),
  q("sq-bg8-45",pd,"advocacy","A patient needs a wheelchair ramp at home but cannot afford one.","How would you help a patient access home modifications?","I would connect the patient with social work for community resources, investigate Medicaid waiver programs, contact local charitable organizations like Habitat for Humanity, explore VA benefits if applicable, and research grant programs for home modifications. I would ensure the need is documented in the discharge plan so it is not forgotten. Home accessibility is a critical determinant of safe discharge.","Home modification resource mobilization.","beginner"),
  q("sq-bg8-46",ip,"clinical_judgment","A patient with Guillain-Barré syndrome develops ascending weakness.","What is the critical monitoring priority for GBS?","GBS causes ascending paralysis that can affect respiratory muscles. The critical priority is respiratory monitoring—I would track FVC (forced vital capacity) every 4 hours. If FVC drops below 20 mL/kg or NIF (negative inspiratory force) is worse than -30 cmH2O, the patient needs intubation. I would also monitor for autonomic dysfunction (blood pressure lability, arrhythmias) and pain management.","GBS respiratory monitoring with intubation criteria.","advanced"),
  q("sq-bg8-47",ws,"patient_safety","A patient at risk for falls is found standing on their bed.","How would you manage unsafe patient behavior?","I would approach calmly and assist them down safely: 'I need you to sit down so you do not fall and hurt yourself. Let me help you.' I would assess why they were standing on the bed—reaching for something, confusion, or purposeful behavior. I would modify the environment, reassess fall prevention interventions, and consider a sitter if behavior is recurring and dangerous.","Immediate safe behavior correction with root cause assessment.","intermediate"),
  q("sq-bg8-48",ct,"documentation_challenges","You need to document patient education and the patient's understanding.","How would you document patient education effectively?","I would document: topics covered, methods used (verbal, written, demonstration), the patient's response and engagement level, teach-back results, barriers to learning identified, and plans for follow-up education. Example: 'Instructed on insulin self-injection technique using demonstration. Patient performed return demonstration correctly. Verbalized understanding of signs of hypoglycemia. Written materials provided.'","Comprehensive education documentation with teach-back results.","beginner"),
  q("sq-bg8-49",cn,"career_advancement","You want to get involved in nursing policy.","How would you contribute to nursing policy development?","I would join professional nursing organizations that influence policy, attend legislative advocacy events, write to legislators about nursing issues, participate in public comment periods for healthcare regulations, and join hospital policy committees. I would stay informed about healthcare policy trends through professional publications. Nursing's voice in policy directly affects patient care quality.","Nursing policy engagement pathways.","intermediate"),
  q("sq-bg8-50",ip,"behavioral","You are asked about your experience with end-of-life care.","How have end-of-life experiences shaped your nursing practice?","Caring for a hospice patient during my community health rotation profoundly impacted me. I learned that nursing at the end of life is not about doing less—it is about doing different things with greater intention. Comfort measures, family support, and dignified care became my focus. I learned to be comfortable with silence, grief, and the privilege of being present during life's final moments.","End-of-life care reflection with professional growth.","intermediate"),
  q("sq-bg8-51",ws,"interdisciplinary_communication","You need to participate in a goals-of-care conversation with a family.","How would you prepare for and contribute to a goals-of-care meeting?","I would review the patient's clinical trajectory, document current functional status, prepare nursing observations about the patient's comfort and quality of life, and identify the patient's expressed wishes. During the meeting, I would share my nursing perspective on daily patient experience, support the family emotionally, and help translate medical information into understandable terms.","Nursing contribution to goals-of-care conversations.","intermediate"),
  q("sq-bg8-52",pd,"ethical_dilemmas","A patient requests genetic testing that reveals implications for family members.","How would you navigate genetic information disclosure?","I would ensure the patient understands the implications of genetic test results for their biological relatives. I would respect the patient's autonomy regarding whether to share results with family members. I would provide resources for genetic counseling. I would not disclose genetic information to family members without the patient's consent, while encouraging the patient to consider informing at-risk relatives.","Genetic information confidentiality with family implications.","advanced"),
  q("sq-bg8-53",ct,"critical_thinking_drills","A patient's calcium is 12.5 mg/dL.","What does hypercalcemia indicate?","Calcium of 12.5 (normal 8.5-10.5) indicates significant hypercalcemia. Common causes include malignancy, hyperparathyroidism, vitamin D toxicity, and immobilization. Symptoms include confusion, constipation, polyuria, muscle weakness, and cardiac arrhythmias. I would ensure IV hydration, hold calcium supplements, place on cardiac monitoring, check PTH levels, and notify the provider. Severe hypercalcemia above 14 is a medical emergency.","Hypercalcemia assessment with multi-system monitoring.","intermediate"),
  q("sq-bg8-54",ws,"difficult_coworkers","A colleague complains about every assignment they receive.","How would you manage chronic complaining from a colleague?","I would address it if it affects morale: 'I understand some assignments are more challenging. When we complain constantly, it brings down the whole team's energy. What specifically about the assignments concerns you?' If there are legitimate concerns, I would encourage them to address it with the charge nurse. Chronic complaining without solutions is different from constructive feedback.","Redirecting complaints toward constructive solutions.","beginner"),
  q("sq-bg8-55",ip,"clinical_judgment","A patient receiving BiPAP develops gastric distension.","What causes gastric distension during BiPAP?","BiPAP delivers positive pressure that can force air into the stomach, causing aerophagia and gastric distension. This is uncomfortable and can impair diaphragmatic function. I would assess for abdominal distension, place an NG tube if ordered to decompress the stomach, adjust BiPAP pressures if possible, and ensure proper mask fit. I would communicate the issue to the respiratory therapist and provider.","BiPAP complication management.","intermediate"),
  q("sq-bg8-56",pd,"patient_communication","A patient with aphasia after a stroke is frustrated with communication barriers.","How would you facilitate communication with an aphasic patient?","I would use a multimodal approach: communication boards with pictures and words, yes/no questions initially, gestures, writing if motor function allows, speech therapy consultation, and electronic communication devices. I would be patient, allow time for responses, and never complete their sentences. I would involve family members who know the patient's communication patterns.","Aphasia communication strategies.","intermediate"),
  q("sq-bg8-57",cn,"probation_period","You want to document your clinical growth for your portfolio.","How would you track clinical growth during probation?","I would maintain a clinical growth journal documenting: new skills mastered, challenging situations managed, feedback received and actions taken, patient outcomes I contributed to, and professional development completed. I would collect anonymized case examples that demonstrate my clinical reasoning. This portfolio is valuable for evaluations, job applications, and professional reflection.","Clinical growth portfolio development.","beginner"),
  q("sq-bg8-58",ip,"clinical_judgment","A patient with chronic liver disease develops hepatorenal syndrome.","What is hepatorenal syndrome and how would you manage it?","Hepatorenal syndrome is functional renal failure in patients with advanced liver disease, caused by severe splanchnic vasodilation and renal vasoconstriction. I would monitor urine output strictly, ensure adequate volume status, administer vasopressin analogs (terlipressin) or midodrine/octreotide as ordered, hold nephrotoxic medications, and notify both the hepatologist and nephrologist. Liver transplantation is often the definitive treatment.","Hepatorenal syndrome management.","advanced"),
  q("sq-bg8-59",ws,"handoff_communication","You are receiving a patient from the PACU after anesthesia.","What specific information do you need from a PACU handoff?","I would need: type of anesthesia and any complications, vital sign trends during recovery, pain management given and effectiveness, intake and output during surgery, blood loss estimate, current drip rates, dressing status, drain output, airway status, consciousness level, last assessment time, and any pending orders. I would also need to know about antiemetic needs and positioning restrictions.","Comprehensive PACU-to-floor handoff requirements.","intermediate"),
  q("sq-bg8-60",ct,"new_nurse_anxiety","You feel like nursing is not what you expected.","How would you manage career disillusionment?","I would separate realistic adjustment from genuine career mismatch. The first year of nursing rarely matches expectations—the learning curve, emotional intensity, and workload can be overwhelming. I would give myself at least 12-18 months before making career judgments. I would seek mentorship, explore different units, and focus on the moments that remind me why I chose nursing. If after adequate time the profession truly does not fit, that is also okay to acknowledge.","Distinguishing adjustment from career mismatch.","beginner"),
  q("sq-bg8-61",pd,"advocacy","A patient's cultural healing practices are dismissed by the medical team.","How would you advocate for cultural healing practice inclusion?","I would educate the team about the patient's cultural practices and their importance for holistic healing. I would research whether the practices are safe alongside medical treatment. I would facilitate conversation between the patient, their cultural/spiritual advisor, and the medical team. I would document the patient's cultural needs in the care plan and advocate for integrative accommodation.","Cultural practice integration advocacy.","intermediate"),
  q("sq-bg8-62",ip,"clinical_judgment","A patient on amiodarone develops thyroid dysfunction.","What thyroid complications can amiodarone cause?","Amiodarone contains iodine and can cause both hypothyroidism and hyperthyroidism. Amiodarone-induced thyrotoxicosis (AIT) is more dangerous and can exacerbate cardiac arrhythmias. I would monitor thyroid function tests regularly, assess for symptoms of thyroid dysfunction, and notify the cardiologist about any changes. Managing amiodarone thyroid effects requires careful coordination between cardiology and endocrinology.","Amiodarone thyroid monitoring requirements.","advanced"),
  q("sq-bg8-63",ws,"patient_safety","A cognitively impaired patient is pulling at their IV line.","How would you prevent IV line disruption in a confused patient?","I would use arm board stabilization, cover the IV site with a transparent dressing and additional tape, use a long-sleeve gown to conceal the tubing, apply distraction techniques, ensure adequate pain management (IV pulling may indicate discomfort), and consider mittens or hand covers as alternatives to restraints. I would reassess the IV necessity and consider heparin lock if continuous infusion is not essential.","Non-restraint IV protection strategies.","beginner"),
  q("sq-bg8-64",cn,"career_advancement","You want to develop your public health nursing skills.","How would you prepare for public health nursing?","I would develop population health assessment skills, learn about epidemiology and disease surveillance, understand community health promotion strategies, and pursue CPH certification. I would gain experience in case management, disease investigation, and community education. Public health nursing requires a systems-level perspective rather than individual patient focus.","Public health nursing preparation.","intermediate"),
  q("sq-bg8-65",ip,"star_examples","Tell me about a time you demonstrated critical thinking.","Describe a clinical situation where critical thinking made a difference.","A post-operative patient's vital signs were technically within normal limits, but I noticed a subtle trend: gradually increasing heart rate and slightly decreasing blood pressure over 4 hours. Individually, each vital sign was acceptable, but the trend concerned me. I notified the surgeon, who ordered a stat hemoglobin—it had dropped from 10 to 7. The patient was hemorrhaging internally and went back to surgery. The trend recognition saved their life.","Pattern recognition and trend analysis saving lives.","intermediate"),
  q("sq-bg8-66",ct,"documentation_challenges","You need to document a skin assessment finding that could be a pressure injury or a moisture-associated lesion.","How would you differentiate and document unclear skin findings?","I would describe objectively: exact location, size, wound bed characteristics, surrounding skin condition, presence of moisture or incontinence, and relationship to bony prominences. Pressure injuries occur over bony prominences; moisture lesions are in skin folds or perianal areas. I would request wound care nursing consultation for definitive staging and management recommendations.","Objective skin assessment documentation with consultation request.","intermediate"),
  q("sq-bg8-67",pd,"workplace_bullying","You are excluded from educational opportunities offered to other new nurses.","How would you address educational opportunity exclusion?","I would request the same opportunities directly: 'I noticed the CE workshop on cardiac monitoring is being offered to other new nurses. I would like to participate as well. How can I register?' I would document any pattern of exclusion and discuss it with my manager. Equal access to education is essential for professional development and patient safety.","Proactive education access request.","beginner"),
  q("sq-bg8-68",ws,"delegation","You need to delegate to an agency nurse unfamiliar with your unit.","How would you delegate to agency staff safely?","I would provide a brief unit orientation, explain unique protocols, identify where emergency equipment is located, and assign patients within the agency nurse's skill set. I would check in frequently and be available for questions. I would verify the agency nurse's credentials and comfort level with the assigned patients. Agency staff unfamiliarity requires additional oversight.","Safe agency staff delegation with enhanced oversight.","intermediate"),
  q("sq-bg8-69",ip,"clinical_judgment","A patient develops syndrome of inappropriate antidiuretic hormone.","How would you manage SIADH?","SIADH causes excessive water retention and dilutional hyponatremia. I would restrict fluids (typically 800-1000 mL/day), monitor serum sodium and osmolality, administer salt tablets or hypertonic saline per orders, check urine specific gravity, and monitor for neurological changes from hyponatremia. I would address the underlying cause (medications, CNS disorders, lung disease, malignancy).","SIADH management with fluid restriction.","advanced"),
  q("sq-bg8-70",cn,"career_advancement","You are interested in neonatal nursing.","How would you prepare for NICU nursing?","I would obtain NRP (Neonatal Resuscitation Program) certification, pursue RNC-NIC certification, develop skills in neonatal assessment and developmental care, learn about common neonatal conditions and ventilator management, and understand the unique family-centered care needs of NICU families. NICU nursing requires meticulous attention to detail with tiny patients and strong family communication skills.","Neonatal nursing specialization pathway.","intermediate"),
  q("sq-bg8-71",ip,"clinical_judgment","A patient on methotrexate develops stomatitis, diarrhea, and pancytopenia.","What does this presentation indicate about methotrexate?","These symptoms indicate methotrexate toxicity affecting the rapidly dividing cells of the GI tract and bone marrow. I would hold the medication immediately, check the methotrexate level, administer leucovorin (folinic acid) rescue as ordered, monitor blood counts and renal function, provide supportive care for stomatitis and diarrhea, and notify the oncologist. Leucovorin is the antidote for methotrexate toxicity.","Methotrexate toxicity with leucovorin rescue.","advanced"),
  q("sq-bg8-72",ws,"patient_safety","A patient on continuous tube feeding aspirates.","How would you manage aspiration during tube feeding?","I would stop the tube feeding immediately, suction the airway, turn the patient to their side, assess respiratory status, provide supplemental oxygen, and call for help. I would notify the provider and anticipate a chest X-ray. I would review preventive measures: head of bed elevation to 30-45 degrees, gastric residual monitoring, and proper tube placement verification before each feeding.","Tube feeding aspiration emergency response.","intermediate"),
  q("sq-bg8-73",pd,"ethical_dilemmas","A patient's family is pressuring you to provide information you believe is protected.","How would you handle family pressure for protected information?","I would remain firm while empathetic: 'I understand your concern for your family member. However, I am legally and ethically bound to protect their health information. The patient has the right to decide what information is shared. I encourage you to discuss your concerns directly with them.' I would not disclose information regardless of family pressure.","HIPAA compliance under family pressure.","beginner"),
  q("sq-bg8-74",ct,"critical_thinking_drills","A patient's lipase is 500 U/L.","What does an elevated lipase indicate?","Lipase above 3 times normal (normal 10-140 U/L) strongly suggests acute pancreatitis. I would assess for epigastric pain radiating to the back, nausea, vomiting, and abdominal tenderness. I would keep the patient NPO, ensure IV hydration, administer pain management, and monitor for complications including organ failure and necrotizing pancreatitis. I would also assess for gallstones and alcohol use as common causes.","Lipase interpretation for pancreatitis diagnosis.","intermediate"),
  q("sq-bg8-75",ip,"scenario_responses","A patient is anxious about a procedure and asks if it will hurt.","How would you address pre-procedure anxiety honestly?","I would be honest while reassuring: 'I want to be upfront with you—you may feel some pressure and brief discomfort during the procedure. However, we use numbing medication and pain management to minimize that. Many patients say it was not as bad as they expected. I will be right here with you throughout, and if you need a break, just tell me.'","Honest pre-procedure anxiety management.","beginner"),
  q("sq-bg8-76",ws,"interdisciplinary_communication","A consulting specialist makes recommendations that contradict the primary team's plan.","How would you manage contradictory consultant recommendations?","I would document the specialist's recommendations clearly, notify the primary team about the conflicting advice, and advocate for a direct discussion between the consultant and primary physician. I would not independently choose which recommendations to follow. The primary team is responsible for synthesizing all consultant input into a cohesive care plan.","Consultant contradiction communication.","intermediate"),
  q("sq-bg8-77",ct,"time_management","You need to coordinate care with multiple departments for diagnostic tests.","How would you coordinate multi-department scheduling?","I would identify all scheduled tests and their preparation requirements (NPO status, medication holds, contrast timing). I would communicate with each department about timing preferences, coordinate with transport, and ensure the patient is prepared for each test. I would create a patient-specific schedule board to track test status and results.","Multi-department test coordination.","beginner"),
  q("sq-bg8-78",pd,"patient_communication","A patient is bargaining about their treatment plan.","How would you respond to a patient bargaining about care requirements?","I would listen to understand their underlying concern: 'I hear that you would like to modify your treatment plan. Can you help me understand what specifically concerns you?' I would explore whether there are alternative approaches that meet both clinical needs and patient preferences. I would explain non-negotiable safety requirements while remaining flexible on preferences.","Understanding-based negotiation with patient preferences.","beginner"),
  q("sq-bg8-79",cn,"probation_period","You want to discuss your career trajectory with your manager.","How would you initiate a career development conversation?","I would schedule a meeting: 'I would like to discuss my career development. I am committed to this unit and want to understand what growth opportunities exist. I am interested in [specific areas] and would appreciate your guidance on how to develop toward those goals within our organization.' Coming with specific interests shows initiative and planning.","Proactive career development dialogue.","beginner"),
  q("sq-bg8-80",ip,"clinical_judgment","A patient on a nicardipine drip for hypertensive emergency has a sudden blood pressure drop.","How would you manage hypotension on an antihypertensive drip?","I would reduce or stop the drip immediately, lower the head of bed, administer IV fluid bolus, recheck blood pressure every 5 minutes, and notify the provider. I would assess for other causes of hypotension beyond the drip effect. I would document the blood pressure trend and the drip rate at the time of the drop. I would not restart the drip at the same rate.","Antihypertensive drip titration response.","intermediate"),
  q("sq-bg8-81",ws,"difficult_coworkers","A nurse on your unit has a negative attitude about evidence-based practice changes.","How would you engage a colleague resistant to EBP changes?","I would acknowledge their experience while presenting evidence: 'I understand this is different from how we have been doing it. The new evidence shows that this approach reduces [complication] by [percentage]. Your experience is valuable—can you help us implement this in a way that works with our workflow?' Involving resistant staff in implementation often converts them into champions.","Engaging resistant staff through involvement.","intermediate"),
  q("sq-bg8-82",ct,"critical_thinking_drills","A patient's brain natriuretic peptide drops from 1200 to 400 after treatment.","What does a declining BNP trend indicate?","A declining BNP indicates improvement in cardiac wall stress and heart failure symptoms—the treatment is working. BNP trends are more clinically useful than single values. A 30% or greater reduction suggests significant clinical improvement. I would correlate with the patient's symptoms: reduced dyspnea, decreased edema, improved exercise tolerance, and weight loss from diuresis.","BNP trending as treatment response marker.","intermediate"),
  q("sq-bg8-83",pd,"advocacy","A patient needs a specialized bed for their condition but the hospital has none available.","How would you manage specialized equipment shortages?","I would contact equipment supply, explore rental options, check with other units for available equipment, escalate the need through the charge nurse and management, and document the clinical necessity. I would implement interim measures: more frequent repositioning, additional padding, and mattress overlays. I would not accept an equipment shortage as an excuse for inadequate care.","Equipment shortage problem-solving with interim measures.","intermediate"),
  q("sq-bg8-84",ip,"clinical_judgment","A patient develops thyroid storm with severe tachycardia, high fever, and agitation.","How would you manage thyroid storm?","Thyroid storm is a life-threatening thyrotoxic crisis. I would administer beta-blockers for heart rate control (propranolol), propylthiouracil or methimazole to block thyroid hormone synthesis, iodine solution (given after antithyroid medication) to block hormone release, corticosteroids to prevent peripheral conversion, and aggressive cooling measures. ICU monitoring is essential. This has a high mortality rate without treatment.","Thyroid storm emergency management protocol.","advanced"),
  q("sq-bg8-85",cn,"career_advancement","You want to develop expertise in cardiac rehabilitation.","How would you pursue cardiac rehab nursing?","I would develop expertise in cardiac assessment, exercise physiology, risk factor modification, and patient education. I would pursue cardiac rehabilitation certification. I would learn about stress testing, exercise prescription, and motivational interviewing for lifestyle changes. Cardiac rehab nursing combines clinical expertise with health coaching and patient empowerment.","Cardiac rehabilitation nursing pathway.","intermediate"),
  q("sq-bg8-86",ws,"patient_safety","A patient is at risk for elopement from the facility.","How would you manage elopement risk?","I would implement elopement precautions per policy: wander guard bracelet, bed and door alarms, 1:1 sitter if indicated, locked unit if applicable, and frequent assessments. I would understand the legal framework for detaining patients—patients without psychiatric holds or court orders cannot be physically prevented from leaving unless they lack capacity and face imminent danger.","Legal-aware elopement prevention.","intermediate"),
  q("sq-bg8-87",ct,"documentation_challenges","You are documenting a multi-system assessment for a complex patient.","How would you efficiently document a complex multi-system assessment?","I would use a head-to-toe systematic approach, document by exception (noting normals briefly and abnormals in detail), use standardized assessment forms to ensure completeness, and focus detailed narrative on systems with active problems. I would avoid redundancy between flowsheet and narrative documentation. Efficient complex documentation combines thoroughness with conciseness.","Efficient complex assessment documentation.","intermediate"),
  q("sq-bg8-88",ip,"behavioral","Tell me about a time you showed compassion under difficult circumstances.","How do you maintain compassion during challenging situations?","I cared for a verbally abusive patient during clinical. Instead of responding defensively, I maintained a calm, caring presence. I later learned they were processing a devastating diagnosis and their behavior was driven by fear. That experience taught me that the patients who seem most difficult often need the most compassion. Their behavior is usually about their suffering, not about me.","Compassion despite difficult patient behavior.","beginner"),
  q("sq-bg8-89",ws,"medication_error","A medication comes back from pharmacy in a different concentration than expected.","How would you handle an unexpected medication concentration?","I would not administer it until verified. I would call pharmacy to confirm the concentration is correct, recalculate the dose based on the new concentration, and ensure my pump programming matches the actual concentration. Concentration errors are particularly dangerous with high-alert medications like insulin, heparin, and vasopressors. Always verify concentration independently.","Concentration verification as medication safety practice.","intermediate"),
  q("sq-bg8-90",pd,"ethical_dilemmas","You are asked to participate in care for a patient who committed a violent crime against a nurse.","How would you manage caring for someone who harmed a colleague?","I would acknowledge the emotional difficulty while maintaining professional standards. If I could not provide unbiased care, I would request reassignment without judgment. I would implement appropriate safety precautions. I would process my feelings through debriefing and EAP. Providing professional care does not require emotional acceptance of the patient's actions.","Self-awareness with professional care maintenance.","advanced"),
  q("sq-bg8-91",ip,"clinical_judgment","A patient with endocarditis develops a sudden focal neurological deficit.","What complication has occurred?","A sudden focal neurological deficit in an endocarditis patient indicates a septic embolism to the brain—a vegetation from the infected heart valve has broken off and traveled to the cerebral circulation. I would perform a rapid neurological assessment, call a stroke code, ensure blood cultures are current, and notify the infectious disease and neurology teams. Imaging will determine if the embolism is ischemic or hemorrhagic.","Septic embolism recognition in endocarditis.","advanced"),
  q("sq-bg8-92",cn,"performance_evaluation","You want to transition from a floor nurse to a leadership position.","How would you demonstrate readiness for nursing leadership?","I would show readiness through actions: leading unit projects, mentoring peers, resolving conflicts constructively, participating in shared governance, demonstrating financial awareness, and contributing to quality improvement. I would document these accomplishments for my evaluation. Leadership readiness is demonstrated through consistent behavior, not just expressed interest.","Action-based leadership readiness demonstration.","intermediate"),
  q("sq-bg8-93",ct,"critical_thinking_drills","A patient's urine output has been less than 20 mL/hour for 4 hours.","What does persistent oliguria indicate?","Urine output less than 0.5 mL/kg/hr for 4+ hours suggests acute kidney injury from prerenal (hypovolemia, cardiogenic shock), intrarenal (nephrotoxic drugs, contrast), or postrenal (obstruction) causes. I would assess fluid status, review nephrotoxic medications, check BUN/creatinine, ensure bladder is not distended, and notify the provider. Fluid challenge may be ordered if prerenal cause is suspected.","Oliguria evaluation with AKI staging.","intermediate"),
  q("sq-bg8-94",ws,"handoff_communication","You are transferring a patient to a long-term care facility.","What information is critical for a long-term care transfer?","I would provide: comprehensive medical history, current medications with last dose times, allergies, dietary requirements, mobility level, cognitive status, wound care instructions, advance directives, insurance information, emergency contacts, pending appointments, and any behavioral management strategies. I would also include personal preferences that affect daily care quality.","Long-term care transfer communication.","beginner"),
  q("sq-bg8-95",pd,"patient_communication","A patient is grieving the loss of their independence.","How would you support a patient mourning independence loss?","I would validate their grief: 'Losing the ability to do things you used to do easily is a real loss, and it is okay to grieve that.' I would help them identify remaining capabilities and strengths, set achievable independence goals, explore adaptive equipment, and connect them with OT for independence maximization. I would involve psychology or social work for ongoing grief support.","Independence loss grief support.","intermediate"),
  q("sq-bg8-96",ip,"clinical_judgment","A patient on lithium develops coarse tremor, vomiting, and confusion.","What does this presentation indicate?","These symptoms indicate lithium toxicity (therapeutic range 0.6-1.2 mEq/L). I would hold the medication, check stat lithium level, BMP, and renal function, ensure IV hydration to promote lithium excretion, place on cardiac monitoring, and notify the provider. Severe toxicity may require hemodialysis. I would check for precipitating factors: dehydration, NSAID use, or renal impairment.","Lithium toxicity recognition and management.","advanced"),
  q("sq-bg8-97",ws,"delegation","You need to delegate wound measurement to a nurse with less wound care experience.","How would you ensure accurate wound measurement delegation?","I would demonstrate proper measurement technique: length (head-to-toe direction), width (perpendicular to length), and depth using a cotton-tipped applicator. I would show how to assess tunneling and undermining using clock-face directions. I would verify their measurements match mine on one wound before delegating independently. I would provide a wound assessment reference card.","Wound measurement education with competency verification.","intermediate"),
  q("sq-bg8-98",ct,"time_management","You are struggling to complete all required education modules during orientation.","How would you manage orientation education requirements?","I would create a schedule distributing modules across the orientation period, prioritize safety-critical modules first, use downtime during slow periods for online modules, and communicate with my educator about the timeline. I would not rush through modules—understanding the content is more important than checking boxes. I would ask for protected time if the workload prevents completion.","Strategic education module scheduling.","beginner"),
  q("sq-bg8-99",pd,"advocacy","A patient needs an interpreter but the family member is interpreting instead.","How would you ensure professional interpretation?","I would explain: 'I appreciate your family's help. However, for medical accuracy and your privacy, we need to use a certified medical interpreter for clinical discussions. Family members may unintentionally filter or alter information. Let me arrange a professional interpreter.' I would use phone or video interpretation if in-person is unavailable. Medical interpretation is a patient safety issue.","Professional interpretation over family translation.","beginner"),
  q("sq-bg8-100",cn,"career_advancement","You want to develop expertise in oncology nursing.","How would you specialize in oncology nursing?","I would seek employment in an oncology unit or cancer center, pursue OCN (Oncology Certified Nurse) certification, develop expertise in chemotherapy administration and side effect management, learn about clinical trials, and build competency in palliative and end-of-life care. I would develop strong emotional resilience skills. Oncology nursing combines advanced clinical care with deep human connection.","Oncology nursing specialization pathway.","intermediate"),
];
